I'd suggest that you use the `AssignableFrom` method for these checks. This will properly pick up more complicated unions such as those generated by the use `oneOf` in a Pulumi schema. This will also allow you to remove the `resolveUnderlyingType` method.

```suggestion
	// This check is necessary due to #4703
	to = model.ResolveOutputs(to)
	if to == model.DynamicType {
		return nil, false
	}
	switch {
	case to.AssignableFrom(model.BoolType):
		if stringLiteral, ok := extractStringValue(from); ok {
			if v, err := convert.Convert(cty.StringVal(stringLiteral), cty.Bool); err == nil {
				value = v
			}
		}
	case to.AssignableFrom(model.IntType):
		if stringLiteral, ok := extractStringValue(from); ok {
			if v, err := convert.Convert(cty.StringVal(stringLiteral), cty.Bool); err == nil {
				value = v
			}
		}
	case to.AssignableFrom(model.IntType), to.AssignableFrom(model.NumberType):
		if stringLiteral, ok := extractStringValue(from); ok {
			if v, err := convert.Convert(cty.StringVal(stringLiteral), cty.Bool); err == nil {
				value = v
			}
		}
