@BenFrantzDale, good catch. I think 4 can be easily implemented with the following wrapper:
```c++
template <T>
class thread_safe_optional {
    std::atomic<bool> m_initialized{false};
    union {
        T m_value;
    }

    thread_safe_optional( const atomic_optional & other ) = delete;
public:
    thread_safe_optional() = default;
    ~thread_safe_optional() {
        if (m_initialized.load(std::memory_order_relaxed)) {
            m_value.~T();
        }
    }
    template <class... Args>
    T& unsafe_emplace( Args&&... args ) {
        new (&m_value) T(std::forward<Args>(args)...);
        return m_value;
    }
    T& get() {
        spin_wait_while_eq(m_initialized, false);
        return m_value;
    }
};

